const a={name:"Salvia",icon:"salvia",category:"kryddor",family:"Kransblommiga",familyLatin:"Lamiaceae",perennial:!0,lifespan:"4-6 år (förvedas med tiden)",difficulty:"Medel",difficultyWhy:"Själva odlingen är enkel, men övervintring är den stora utmaningen. Salvia hatar blöta fötter på vintern och kräver väldränerad jord och skydd i kallare zoner. Behöver också föryngringsbeskärning vart 3-4 år.",zones:{outdoor:[1,2,3,4,5],indoor:[1,2,3,4,5,6,7,8],greenhouse:[1,2,3,4,5,6,7,8]},days:"60-70 (blad), 100-130 (från frö till full planta)",spacing:"30 cm",rowSpacing:"35 cm",depth:"0.2 cm",depthNote:"Ljusgroddare - tryck fast men täck knappt",ph:{min:6,max:7.5,ideal:6.5},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Medelhavsväxt som kräver minst 6 timmars direkt sol per dag. I halvskugga blir salvian gles och smaken svagare. Söderläge mot en varm mur? Perfekt - det är som ett litet medelhavsparadis."},temperature:{min:-15,max:35,ideal:"15-25°C",detail:"Klarar ner till -15°C med snötäcke och väldränerad jord. Men det är inte kylan som dödar henne - det är fukten. En blöt höst följd av frost tar kål på salvian snabbare än ren vinterköld."},wind:{level:"Tålig",detail:"Halv buske med vedartade stammar - klarar vind bättre än de flesta kryddor. Men ett skyddat, soligt läge ger alltid bäst resultat och bättre övervintring."}},watering:{need:"Låg",icon:"water",summary:"Torktålig medelhavsväxt som mår bäst av att inte bli bortskämd med vatten. Bättre att låta jorden torka ut lite mellan vattningarna än att riskera blöta fötter.",phases:[{phase:"Nyplanterad (första månaden)",need:"Medel",tip:"Vattna regelbundet tills plantan etablerat sig - men aldrig så det står vatten. Korta, frekventa givor är bättre än att dränka henne."},{phase:"Etablerad planta",need:"Låg",tip:"Vattna bara vid långvarig torka. Salvian har djupa rötter och hittar fukt på egen hand. Övervattning är det farligaste du kan göra."},{phase:"Krukodlad",need:"Medel",tip:"I kruka torkar jorden snabbare - kolla med fingret och vattna när de översta 3 cm är torra. Bra dränering i botten är ett absolut måste."}],mistakes:["Övervattning - den absolut vanligaste dödsorsaken för salvia. Rötterna ruttnar i blöt jord","Vattnar sent på hösten - fuktig jord + frost = garanterad övervintringsdöd","Planterar i tung lerjord utan dränering - bäddar för problem"],tip:"Blanda in grus eller perlite i jorden vid plantering. Tänk medelhavsjord - mager, torr och väldränerad. Salvian tackar dig med intensiv arom."},soil:"Salvia vill ha genomsläpplig, gärna kalkrik jord med bra dränering. Tänk medelhavsjord - sandig, mager och aldrig vattensjuk. Blanda gärna in grus eller sand om du har tung jord.",soilTips:["Genomsläpplig jord är A och O - blanda in grus eller sand i tung lerjord","Kalkrik jord uppskattas - strö lite trädgårdskalk om du har sur jord","Behöver inte rik jord - mager jord ger faktiskt starkare arom","I kruka: blanda planteringsjord med 1/3 perlite eller grus för bra dränering"],timeline:{1:[{phase:"Förodling inomhus",months:"Feb-mar",icon:"indoor"},{phase:"Utplantering",months:"Maj",icon:"seedling"},{phase:"Blomning",months:"Jun-aug",icon:"flower"},{phase:"Skörd (löpande)",months:"Jun-okt",icon:"harvest"},{phase:"Vintertäckning",months:"Nov",icon:"snowflake"}],4:[{phase:"Förodling inomhus",months:"Mar-apr",icon:"indoor"},{phase:"Utplantering",months:"Slutet av maj-jun",icon:"seedling"},{phase:"Blomning",months:"Jul-aug",icon:"flower"},{phase:"Skörd (löpande)",months:"Jul-sep",icon:"harvest"},{phase:"Vintertäckning",months:"Okt",icon:"snowflake"}],6:[{phase:"Förodling inomhus",months:"Mar-apr",icon:"indoor"},{phase:"Utplantering",months:"Jun",icon:"seedling"},{phase:"Skörd",months:"Jul-aug",icon:"harvest"},{phase:"Storskord före frost",months:"Sep",icon:"harvest"}]},nutritionData:[{month:"Apr",N:2,P:1,K:1},{month:"Maj",N:3,P:2,K:2},{month:"Jun",N:4,P:3,K:3},{month:"Jul",N:4,P:3,K:3},{month:"Aug",N:3,P:2,K:2},{month:"Sep",N:1,P:1,K:1}],nutritionTips:[{timing:"Vår (april-maj)",tip:"En lätt giva kompost runt plantan räcker gott. Salvia är anspråkslös och mår bäst av mager jord - övergödsling ger stor planta men svag smak."},{timing:"Sommar",tip:"Ingen extra gödsling behövs. Salvian klarar sig fint med det som finns i jorden. Mager jord ger faktiskt starkare eteriska oljor."},{timing:"Obs!",tip:"Kväverik gödsel ger frodigt bladverk men slapp växt som övervintrar dåligt. Håll det spartanskt - salvian tackar dig med intensivare arom."}],companions:{good:[{id:"vitkal",name:"Kålväxter",icon:"vegetable",why:"Salvians starka doft avskräcker kålfjärilar och kålmalar. Plantera salvia runt kålodlingen som en naturlig insektsbarriär."},{id:"morot",name:"Morot",icon:"vegetable",why:"Salvian avskräcker morotsflugan med sin intensiva doft. Ett klassiskt och beprövat kompanjonpar."},{id:"rosmarin",name:"Rosmarin",icon:"herb",why:"Medelhavskompisar! Exakt samma krav på sol, dränering och mager jord. Trivs fantastiskt ihop i ett kryddland."},{id:"timjan",name:"Timjan",icon:"herb",why:"Liknande odlingskrav - båda vill ha torrt, magert och soligt. Bildar ett fint medelhavshörn i trädgården."}],bad:[{id:"gurka",name:"Gurka",icon:"vegetable",why:"Salvia hämmar gurkans tillväxt. Helt olika behov - gurkan vill ha fukt och näring, salvian vill ha torrt och magert."},{id:"basilika",name:"Basilika",icon:"herb",why:"Helt olika krav! Basilika vill ha rik, fuktig jord - raka motsatsen till salvia. Deras eteriska oljor sägs dessutom störa varandra."},{id:"lok",name:"Lök",icon:"vegetable",why:"Trivs inte nära varandra - olika krav och kemisk oförenlighet i jorden."}]},rotation:{avoid:[{id:"salvia",name:"Salvia"},{id:"mynta",name:"Mynta"},{id:"basilika",name:"Basilika"},{id:"oregano",name:"Oregano"}],avoidWhy:"Kransblommiga (Lamiaceae) delar jordburna sjukdomar. Plantera inte ny salvia där gammal salvia stått - vänta minst 3 år.",goodBefore:[{name:"Kålväxter"},{name:"Rotgrönsaker"}],goodBeforeWhy:"Salvia lämnar väldränerad, ogödslad jord som passar bra för kål och rotfrukter.",goodAfter:[{id:"artor",name:"Ärtor"},{id:"bondbona",name:"Bondböna"}],goodAfterWhy:"Baljväxter berikar jorden med kväve. Men salvia är perenn - rotation gäller mest när du tar bort en gammal planta."},varieties:[{name:"Kryddsalvia (standard)",zones:[1,2,3,4,5],note:"Den klassiska, grågröna. Härdigast av alla och har odlats i Sverige sedan medeltiden. Ekologiskt frö hos Runåbergs. Kulturarv."},{name:"Extracta",zones:[1,2,3,4],note:"Silvergrå blad, extra aromatisk med blåvioletta blommor. Bra för torkning. Finns hos Impecta."},{name:"Purpurascens",zones:[1,2,3],note:"Mörkt vinröda blad med starkare smak. Vacker i rabatten men något mindre härdig - bäst i sydliga zoner."},{name:"Berggarten",zones:[1,2,3,4],note:"Stora, runda blad och kompakt växt. Blommar sällan - perfekt om du bara vill skörda blad. Favorit bland kockar."}],problems:[{name:"Övervintringsdöd (rotröta)",symptom:"Plantan dör under vintern eller tidig vår. Rötterna är brunsvarta och mjuka.",fix:"Förebygg med väldränerad jord - blanda in grus/sand vid plantering. Täck med granris på hösten. Undvik blöta lägen. Det är fukt, inte kyla, som tar kål på salvian."},{name:"Förvedning",symptom:"Plantan blir kålig och vedartad nerifrån efter 3-4 år, tappar blad.",fix:"Beskär varje vår (april-maj) - skär ner till friskt, grönt ved. Klipp aldrig in i helt bart ved. Föryngra genom sticklingar vart 3-4 år för friska, nya plantor."},{name:"Mjöldagg",symptom:"Vitt, mjölaktigt pulver på bladen, särskilt vid torrt väder med hög luftfuktighet.",fix:"Klipp bort drabbade delar. Ge bättre luftcirkulation. Undvik att vattna ovanifrån."},{name:"Bladlöss",symptom:"Gröna eller svarta små insekter på unga skott.",fix:"Friska plantor i full sol angrips sällan. Spola av med vatten vid behov. Salvian lockar själv nyttoinsekter med sina blommor."}],goodToKnow:[{icon:"tip",title:"Bättre torkad än färsk",text:"Salvia är en av få kryddor som faktiskt är GODARE torkad. Torkningen koncentrerar de eteriska oljorna och ger en mer avrundad, djup smak. De flesta kryddor tappar smak vid torkning - salvian gör tvärtom.",severity:"tip"},{icon:"warning",title:"Fukt dödar - inte kyla",text:"Salvian kan klara -15°C med snötäcke. Men en blöt höst följd av frost? Garanterad död. Väldränerad jord och granristäckning är de bästa livförsäkringarna. Tänk medelhav - torrt, magert, soligt.",severity:"warning"},{icon:"tip",title:"Kålfjärilens fiende",text:"Salvians starka doft avskräcker kålfjärilar och kålmalar. Plantera en rad salvia runt kålodlingen så slipper du halvätna blad. Biologisk bekämpning som dessutom ger dig krydda!",severity:"tip"},{icon:"warning",title:"Beskär varje vår - annars blir hon ful",text:"Utan vårskärning blir salvian vedartad och kal nerifrån efter 3-4 år. Klipp ner till grönt ved i april-maj så hon skjuter friska skott. Eller ta sticklingar och börja om - salvia rotar sig enkelt i fuktig sand.",severity:"warning"},{icon:"tip",title:"Klosterkrydda sedan medeltiden",text:'Namnet Salvia kommer från latinets "salvare" - att rädda. Munkar tog med den till Sverige redan på 800-talet. Ett gammalt latinskt ordspråk lyder: "Varför ska en människa dö som har salvia i sin trädgård?"',severity:"tip"}],sowing:{method:"indoor",label:"Förodling & sådd",description:"Salvia förodlas bäst inomhus på våren. Fröna är ljusgroddare - tryck fast dem på ytan men täck knappt. Gror på 10-21 dagar vid 20-25°C. Sticklingar och delning är snabbare alternativ för den otåliga.",steps:["Fyll krukor med fuktig såjord","Lägg fröna på ytan och tryck fast lätt - täck bara med ett hafs jord (ljusgroddare)","Håll jämnt fuktigt och varmt (20-25°C)","Groning på 10-21 dagar - tålamod krävs!","Gallra till 1 planta per kruka vid 2-3 örtblad","Härda av 1-2 veckor före utplantering","Plantera ut i väldränerad jord på solig plats efter sista frost"],tips:["Sticklingar (juli-aug) ger snabbare resultat - klipp 10 cm kvistar och sätt i fuktig sand","Dela etablerade plantor på våren - enklaste sättet att få nya plantor","Plantera gärna intill en sydvänd mur - extra värme och vindskydd","Blanda in grus i planteringsgropen för bästa dränering"],indoorWeeks:"6-8 veckor före utplantering"},seedSaving:{difficulty:"Medel",type:"Insektspollinerad",biennial:!1,description:"Salvia blommar vanligtvis från andra året. Låt blomställningarna torka på plantan och samla fröna när de mörknat. Groningsförmågan minskar snabbt - använd färskt frö för bäst resultat.",steps:["Låt plantan blomma ut (juni-augusti)","Vänta tills blomställningarna torkar och fröna mörknar (bruna/svarta)","Klipp av blomstjälkarna när fröhusen är bruna men inte helt öppna","Häng upp i papperspåse att eftertorka 1-2 veckor","Skaka ur fröna och rensa bort skal och skräp","Förvara i märkt kuvert eller glasburk, svalt och torrt"],isolation:"Kryddsalvia pollineras av humlor och bin. Håll ca 400 meters avstånd mellan sorter för sortrena frön. I praktiken räcker det ofta med mindre avstånd i en hemmaträdgård.",storageYears:"2-3 år (använd helst färskt frö)",tip:"Sticklingar och delning ger identiska kloner av din favoritplanta - snabbare och säkrare än frö. Men frösådd ger genetisk variation som kan ge spännande resultat!"},storage:{shelfLife:"1-2 veckor (färsk)",methods:[{method:"Torkning (bäst!)",icon:"storage",duration:"1+ år",description:"Bind små knippen och häng upp och ner på varm, luftig plats. Eller torka på galler. Salvia är en av få kryddor som faktiskt blir GODARE av att torkas - aromerna koncentreras.",best:!0},{method:"Frysning",icon:"snowflake",duration:"6-12 månader",description:"Hacka blad och frys i isbitsfack med lite olivolja. Eller frys hela kvistar på plåt och förvara i fryspåse. Behåller smaken bra.",best:!1},{method:"Salviesmör",icon:"storage",duration:"3-6 månader (fryst)",description:"Blanda finhackad salvia i rumstempererat smör, rulla till en rulle i plastfilm och frys. Skiva av vid behov - fantastiskt till pasta och potatis.",best:!1},{method:"Färsk (kort lagring)",icon:"water",duration:"1-2 veckor",description:"Ställ kvistar i ett glas vatten i kylen, eller linda i fuktigt hushållspapper. Salvias vedartade stammar gör att hon håller sig bra.",best:!1}],tips:["Torka hela blad i mörk, tätslutande burk - behåller aromerna fantastiskt länge","Stekta salviablad i smör (30 sek) = krispig delikatess direkt på pastan","Använd halva mängden torkad vs färsk - torkning koncentrerar smaken rejält","Skörda före blomning för starkaste smak i bladen"]},harvestCalc:{minPerSqm:.3,maxPerSqm:.8,unit:"kg"},harvest:{label:"Skörd & användning",method:"Klipp kvistar och blad löpande under säsongen",description:"Skörda genom att klippa hela kvistar - det stimulerar ny tillväxt. Börja plocka när plantan är väletablerad med minst 6-8 bladpar. Skörda aldrig mer än en tredjedel av plantan åt gången.",uses:[{use:"Kött (lamm, fläsk, vilt)",tip:"DEN klassiska lammkryddan. Gnid in köttet med färska eller torkade blad före tillagning. Fungerar fantastiskt till jul-skinka och korv."},{use:"Pasta (burro e salvia)",tip:"Klassisk italiensk rätt: stek salviablad i smör tills de blir krispiga, häll över nykokad pasta. Enkelt, snabbt, gudomligt."},{use:"Torkad krydda",tip:"Torka i knippen och förvara i burk. Använd sparsamt - salvia är stark! Perfekt i grytor, soppor och fyllningar."},{use:"Te",tip:"Salviate (färska eller torkade blad i hett vatten) har traditionellt använts mot halsont. Mild, kryddigt smak som värmer."}]}};export{a as salvia};
